import{_ as e,o as t,c as s,a0 as o}from"./chunks/framework.CEvT70OL.js";const u=JSON.parse('{"title":"Github codespaces","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"05_how_to_use/index.md","filePath":"05_how_to_use/index.md"}'),i={name:"05_how_to_use/index.md"};function c(l,a,r,d,h,p){return t(),s("div",null,[...a[0]||(a[0]=[o('<h1 id="github-codespaces" tabindex="-1">Github codespaces <a class="header-anchor" href="#github-codespaces" aria-label="Permalink to &quot;Github codespaces&quot;">​</a></h1><p><code>TypeScratcher</code> を使う環境を <strong>Github codespaces</strong> で構築します。</p><ul><li>Githubアカウントを作る</li><li>Githubアプリを作る</li><li>アプリでGithubを開く</li><li>レポジトリを作る</li><li><strong>codespaces</strong> を開く</li><li><strong>vite</strong>でスクリプトを起動する</li><li>デバッグする</li></ul><h3 id="codespacesを使う利点" tabindex="-1">Codespacesを使う利点 <a class="header-anchor" href="#codespacesを使う利点" aria-label="Permalink to &quot;Codespacesを使う利点&quot;">​</a></h3><hr><h4 id="クラウド最強のvs-code相当" tabindex="-1">クラウド最強のVS-CODE相当 <a class="header-anchor" href="#クラウド最強のvs-code相当" aria-label="Permalink to &quot;クラウド最強のVS-CODE相当&quot;">​</a></h4><div class="tip custom-block"><p class="custom-block-title">クラウド最強のVS-CODE</p><p>VS-CODE相当の充実した機能をもつ開発環境です。<br> クラウドで利用できる開発環境の中で最強のパフォーマンスを誇ります。</p></div><hr><h4 id="すぐに使える" tabindex="-1">すぐに使える <a class="header-anchor" href="#すぐに使える" aria-label="Permalink to &quot;すぐに使える&quot;">​</a></h4><div class="tip custom-block"><p class="custom-block-title">すぐに使える</p><p>VS-CODE相当のエディターであり、開発にて使用する NODEやGITが初めから用意されている環境です。<br> （ローカルＰＣ上へ環境を用意する場合、最初に環境を整えることが面倒です）</p></div><hr><h4 id="ネットがあればどこでも使える" tabindex="-1">ネットがあればどこでも使える <a class="header-anchor" href="#ネットがあればどこでも使える" aria-label="Permalink to &quot;ネットがあればどこでも使える&quot;">​</a></h4><div class="tip custom-block"><p class="custom-block-title">ネットがあればどこでも</p><p>クラウド上での開発環境です。<br> インターネットにつながる環境＋ブラウザで、どこでも使えます。</p></div><hr><h4 id="無償で使える" tabindex="-1">無償で使える <a class="header-anchor" href="#無償で使える" aria-label="Permalink to &quot;無償で使える&quot;">​</a></h4><div class="tip custom-block"><p class="custom-block-title">無償</p><p>制限はありますが、無償で利用できます。</p></div><hr><h3 id="codespaces-無償-の注意点" tabindex="-1">Codespaces(無償)の注意点 <a class="header-anchor" href="#codespaces-無償-の注意点" aria-label="Permalink to &quot;Codespaces(無償)の注意点&quot;">​</a></h3><h4 id="無償の制限時間" tabindex="-1">無償の制限時間 <a class="header-anchor" href="#無償の制限時間" aria-label="Permalink to &quot;無償の制限時間&quot;">​</a></h4><div class="tip custom-block"><p class="custom-block-title">無償利用時間</p><p>無償で利用できるのは60時間/月です。初学者が使うには十分な時間だと思います。 これを超えると利用できませんが、翌月になれば利用可能時間が元に戻りますので、元通り使えるようになります。</p></div><h4 id="自動削除されることがある" tabindex="-1">自動削除されることがある <a class="header-anchor" href="#自動削除されることがある" aria-label="Permalink to &quot;自動削除されることがある&quot;">​</a></h4><div class="tip custom-block"><p class="custom-block-title">自動削除</p><p>一定期間(30日間)アクセスせずに放置すると『Codespaces』は自動削除されます。<br> 削除されて困る場合はGithubへ変更内容をプッシュして保存しておきましょう。</p></div><h3 id="もっと自由に" tabindex="-1">もっと自由に <a class="header-anchor" href="#もっと自由に" aria-label="Permalink to &quot;もっと自由に&quot;">​</a></h3><p>::: 時間を気にせずに使いたいという方 ご自分のＰＣにて、VS-CODEによる開発環境を整えましょう。<br> または GITHUBへ課金をしましょう。 :::</p>',24)])])}const b=e(i,[["render",c]]);export{u as __pageData,b as default};
